const words=[{word:"Comer",type:"Verbo"},{word:"Correr",type:"Verbo"},{word:"Beber",type:"Verbo"},{word:"Dormir",type:"Verbo"},{word:"Casa",type:"Substantivo"},{word:"Carro",type:"Substantivo"},{word:"Livro",type:"Substantivo"},{word:"Mesa",type:"Substantivo"},{word:"Bonito",type:"Adjetivo"},{word:"Rápido",type:"Adjetivo"},{word:"Forte",type:"Adjetivo"},{word:"Alto",type:"Adjetivo"},{word:"Ele",type:"Pronome"},{word:"Nós",type:"Pronome"},{word:"Eles",type:"Pronome"},{word:"Ela",type:"Pronome"},{word:"Cantar",type:"Verbo"},{word:"Pular",type:"Verbo"}];function shuffle(array){for(let i=array.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[array[i],array[j]]=[array[j],array[i]]}return array}const game=new MemoryGame("gameBoard");function startGame(){game.init(shuffle(words))}document.getElementById("restartBtn").addEventListener("click",startGame),startGame();